module RefModule (
    input clk,
    input rst,
    input en,
    input [15:0] d,
    output reg [15:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst)
        q <= 16'd0;
    else if (en)
        q <= d;
end

endmodule
